sql:
SELECT department, COUNT(*)
FROM faculty
GROUP BY department;

SELECT faculty_id, ROUND(AVG(citation_count), 2) AS average_citations
FROM citation
GROUP BY faculty_id;

SELECT name, department 
FROM faculty 
ORDER BY position;

SELECT AVG(citation_count) 
FROM citation 
WHERE faculty_id = 1;

SELECT f.name, f.research_interests, d.department_name 
FROM faculty f 
INNER JOIN department d ON f.department = d.department_name;

SELECT SUM(
    (julianday(end_date) - julianday(start_date)) * 24 
) AS total_hours
FROM research;

external_knowledge:
- 'sailing the academic seas since before 2010' refers to faculty members hired before 2010;
- 'steering ongoing voyages of discovery' metaphorically refers to faculty members who are involved in research projects that have not ended or are ongoing;
- 'academic harbors' refers to the departments the faculty members belong to;
- 'total navigational stars' is a metaphor for the total number of citations each faculty member has received.

sql:
SELECT AVG(total_citations) AS average_total_citations
FROM (
  SELECT faculty_id, SUM(citation_count) AS total_citations
  FROM citation
  GROUP BY faculty_id
) AS faculty_citations;

external_knowledge:
- "guiding stars" metaphorically refers to faculty members;
- "illuminate the path of knowledge" metaphorically refers to the role of professors in education;
- "titles" refer to the position names of the faculty members;
- "shine brightly as Professors" metaphorically describes their role and status.

sql:
SELECT name, position
FROM faculty
WHERE department = 'Science' AND position = 'Professor';

external_knowledge:
- 'Prolific scholars' refers to faculty members with a high citation rate; 
- 'Recent recognitions' indicates citations received in the past year; 
- 'More than 5 recognitions' means the citation count is greater than 5.

sql:
SELECT citation_id, faculty_id, publication_name, citation_date, citation_count 
FROM citation
WHERE citation_id > 0;

external_knowledge:
- 'seasoned scholars' refers to faculty members;
- 'fertile fields of their expertise' refers to the departments they belong to;
- 'roles they wear' means their positions;
- 'nurturing a garden of no less than a dozen young minds' means advising at least 10 students;
- 'set sail on more than one voyage of discovery' means having more than one research project.

sql:
SELECT COUNT(DISTINCT f.faculty_id)
FROM faculty f
JOIN research r ON f.faculty_id = r.faculty_id;

SELECT SUM(citation_count) AS total_citations 
FROM citation 
WHERE faculty_id = 1;
